SELECT EXISTS(
  SELECT 1
  FROM property
  WHERE id = #{propertyId}
)

SELECT
  id,
  property_type,
  name,
  sgg_cd,
  umd_nm,
  jibun,
  build_year,
  latitude,
  longitude,
  latest_sale_price,
  latest_deposit,
  latest_monthly_rent
FROM property


    AND sgg_cd = #{sggCd}


    AND umd_nm = #{umdNm}


    AND (
      name LIKE CONCAT('%', #{name}, '%')
      OR umd_nm LIKE CONCAT('%', #{name}, '%')
      OR jibun LIKE CONCAT('%', #{name}, '%')
    )


    AND property_type = #{propertyType}


    AND latest_sale_price > 0

      AND latest_sale_price >= #{minPrice}


      AND latest_sale_price <= #{maxPrice}



    AND latest_deposit > 0
    AND latest_monthly_rent = 0

      AND latest_deposit >= #{minPrice}


      AND latest_deposit <= #{maxPrice}



    AND latest_monthly_rent > 0

      AND latest_deposit >= #{minPrice}


      AND latest_deposit <= #{maxPrice}




      AND (
        latest_sale_price >= #{minPrice}
        OR latest_deposit >= #{minPrice}
      )


      AND (
        (latest_sale_price > 0 AND latest_sale_price <= #{maxPrice})
        OR (latest_deposit > 0 AND latest_deposit <= #{maxPrice})
      )



ORDER BY




        latest_sale_price


        latest_deposit


        GREATEST(latest_sale_price, latest_deposit)




    name


    updated_at




    ASC


    DESC


, id DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(id)
FROM property

   AND sgg_cd = #{sggCd} 
   AND umd_nm = #{umdNm} 

    AND (
      name LIKE CONCAT('%', #{name}, '%')
      OR umd_nm LIKE CONCAT('%', #{name}, '%')
      OR jibun LIKE CONCAT('%', #{name}, '%')
    )

   AND property_type = #{propertyType}

SELECT id, exclusive_area, land_area, deposit, monthly_rent, floor, contract_term, contract_type, use_rr_right, pre_deposit, pre_monthly_rent, deal_date FROM rent_deal WHERE property_id = #{propertyId}
AND monthly_rent > 0
AND monthly_rent = 0
ORDER BY deal_date DESC, id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM sale_deal
WHERE property_id = #{propertyId}

SELECT COUNT(*) FROM rent_deal WHERE property_id = #{propertyId}
AND monthly_rent > 0
AND monthly_rent = 0

SELECT id, latitude, longitude
FROM property
WHERE property_type = #{propertyType}
  AND sgg_cd = #{sggCd}
  AND umd_nm = #{umdNm}
  AND jibun = #{jibun}
  AND name = #{name}
  AND build_year = #{buildYear}

